// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

import "./Types.sol";

event ResolverConfigured(
    ResolverType indexed resolverType,
    address indexed resolver,
    uint16 feeBps,
    string label,
    bool active
);

event EscrowCreated(
    uint256 indexed escrowId,
    address indexed client,
    address indexed recipient,
    address token,
    uint256 totalAmount,
    uint64 fundingDeadline,
    ResolverType resolverType
);

event EscrowFunded(
    uint256 indexed escrowId,
    address indexed client,
    uint256 amount
);

event EscrowStatusChanged(
    uint256 indexed escrowId,
    EscrowStatus oldStatus,
    EscrowStatus newStatus
);

event EscrowCancelled(uint256 indexed escrowId, address indexed caller);
event EscrowCompleted(uint256 indexed escrowId, address indexed caller);

event MilestoneCreated(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    uint256 amount,
    uint64 dueDate,
    MilestoneReleaseRule releaseRule,
    string title
);

event MilestoneStatusChanged(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    MilestoneStatus oldStatus,
    MilestoneStatus newStatus
);

event MilestoneSubmitted(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed submitter,
    uint64 reviewDeadline
);

event MilestoneApproved(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed approver
);

event MilestoneRefundApproved(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed approver
);

event FundsReleased(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed recipient,
    uint256 amount
);

event FundsRefunded(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed client,
    uint256 amount
);

event DisputeOpened(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed raiser,
    string reason
);

event DisputeResolved(
    uint256 indexed milestoneId,
    uint256 indexed escrowId,
    address indexed resolver,
    uint256 recipientAmount,
    uint256 clientRefundAmount,
    string resolutionDetails
);

project/contracts/Types.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

enum GlobalReleaseRule {
    DUAL_APPROVAL,
    CLIENT_APPROVAL_AND_TIMEOUT
}

enum MilestoneReleaseRule {
    CLIENT_APPROVAL,
    BOTH_PARTIES_APPROVE,
    CLIENT_APPROVAL_OR_TIMEOUT,
    CUSTOM
}

enum RefundPolicy {
    ON_EXPIRY_IF_UNAPPROVED,
    MEDIATOR_CAN_SPLIT_REFUND,
    MANUAL_ONLY
}

enum ResolverType {
    NONE,
    PLATFORM,
    INDEPENDENT
}

enum EscrowStatus {
    DRAFT,
    AWAITING_FUNDING,
    LIVE,
    IN_REVIEW,
    DISPUTED,
    COMPLETED,
    CANCELLED
}

enum MilestoneStatus {
    PENDING,
    IN_REVIEW,
    APPROVED,
    RELEASED,
    REFUNDED,
    DISPUTED,
    RESOLVED,
    CANCELLED
}

struct ResolverConfig {
    address resolver;
    uint16 feeBps;
    string label;
    bool active;
}

struct CreateEscrowInput {
    string title;
    string description;
    string clientName;
    string recipientName;
    address recipient;
    address token;
    uint256 totalAmount;
    uint64 fundingDeadline;
    GlobalReleaseRule defaultReleaseRule;
    RefundPolicy refundPolicy;
    ResolverType resolverType;
}

struct MilestoneInput {
    string title;
    string description;
    uint256 amount;
    uint64 dueDate;
    MilestoneReleaseRule releaseRule;
    string releaseCondition;
}

struct EscrowData {
    uint256 id;
    string title;
    string description;
    string clientName;
    string recipientName;
    address client;
    address recipient;
    address token;
    uint256 totalAmount;
    uint256 fundedAmount;
    uint256 releasedAmount;
    uint256 refundedAmount;
    uint64 createdAt;
    uint64 fundingDeadline;
    uint64 fundedAt;
    uint64 completedAt;
    GlobalReleaseRule defaultReleaseRule;
    RefundPolicy refundPolicy;
    ResolverType resolverType;
    address resolver;
    uint16 resolverFeeBps;
    EscrowStatus status;
    uint256[] milestoneIds;
}

struct MilestoneData {
    uint256 id;
    uint256 escrowId;
    string title;
    string description;
    uint256 amount;
    uint64 dueDate;
    uint64 submittedAt;
    uint64 reviewDeadline;
    uint64 resolvedAt;
    MilestoneReleaseRule releaseRule;
    RefundPolicy refundPolicy;
    MilestoneStatus status;
    bool clientApproved;
    bool recipientApproved;
    bool clientRefundApproved;
    bool recipientRefundApproved;
    string releaseCondition;
}

struct EscrowSummary {
    uint256 id;
    address client;
    address recipient;
    address token;
    uint256 totalAmount;
    uint256 fundedAmount;
    uint256 releasedAmount;
    uint256 refundedAmount;
    uint64 createdAt;
    uint64 fundingDeadline;
    uint64 fundedAt;
    uint64 completedAt;
    GlobalReleaseRule defaultReleaseRule;
    RefundPolicy refundPolicy;
    ResolverType resolverType;
    address resolver;
    uint16 resolverFeeBps;
    EscrowStatus status;
    uint256 milestoneCount;
}

struct EscrowText {
    string title;
    string description;
    string clientName;
    string recipientName;
}

struct MilestoneSummary {
    uint256 id;
    uint256 escrowId;
    uint256 amount;
    uint64 dueDate;
    uint64 submittedAt;
    uint64 reviewDeadline;
    uint64 resolvedAt;
    MilestoneReleaseRule releaseRule;
    RefundPolicy refundPolicy;
    MilestoneStatus status;
    bool clientApproved;
    bool recipientApproved;
    bool clientRefundApproved;
    bool recipientRefundApproved;
}

struct MilestoneText {
    string title;
    string description;
    string releaseCondition;
}

struct MilestoneView {
    MilestoneSummary summary;
    MilestoneText text;
}

struct EscrowView {
    EscrowSummary summary;
    EscrowText text;
    uint256[] milestoneIds;
    MilestoneView[] milestones;
}
